// ============================================================
// Tarifas de parámetros de Monitoreos 2026 (CENIT).
// Generado de 'Plan de Monitoreos 2026.xlsx' (hojas Tarifas_Aguas/
// Tarifas_Suelos/Tarifas_general). Clave: categoria + nombre normalizado.
// ============================================================

export type CategoriaTarifa = 'agua' | 'suelo' | 'general';

export interface TarifaParametro {
  categoria: CategoriaTarifa;
  parametroNorm: string;
  parametro: string;
  precio: number;
}

/** Normaliza el nombre de un parámetro para casar tarifas (quita sufijo de código, acentos y no-alfanuméricos). */
export function normParametro(s: string): string {
  return s
    .replace(/\s*-\s*\d+\s*$/, '')
    .normalize('NFD').replace(/[̀-ͯ]/g, '')
    .toLowerCase().replace(/[^a-z0-9]/g, '');
}

/** Categoría de tarifa a partir de la matriz de la fila de monitoreos. */
export function categoriaDeMatriz(matriz: string): CategoriaTarifa {
  const m = (matriz || '').toLowerCase();
  if (m.includes('agua') || matriz === 'ARD' || matriz === 'ARnD') return 'agua';
  if (m.includes('suelo') || m.includes('sedimento') || m.includes('lodo')) return 'suelo';
  return 'general';
}

/** Clave de tarifa = `${categoria}|${normParametro(nombre)}`. */
export function claveTarifa(categoria: CategoriaTarifa, parametro: string): string {
  return `${categoria}|${normParametro(parametro)}`;
}

